import{_ as a,o as e,c as o,a2 as r}from"./chunks/framework.ZhLefgN8.js";const u=JSON.parse('{"title":"存入资金","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"portfolio-and-statements/deposit.md","filePath":"zh-CN/portfolio-and-statements/deposit.md"}'),d={name:"portfolio-and-statements/deposit.md"};function l(i,t,h,s,n,p){return e(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="存入资金" tabindex="-1">存入资金 <a class="header-anchor" href="#存入资金" aria-label="Permalink to &quot;存入资金&quot;">​</a></h1><p>存入资金用于将外部银行账户的资金转入长桥香港综合账户，支持港元（HKD）和美元（USD）两种货币。</p><blockquote><p>以上服务由长桥证券（香港）有限公司（BPX066）提供。</p></blockquote><h2 id="页面入口" tabindex="-1">页面入口 <a class="header-anchor" href="#页面入口" aria-label="Permalink to &quot;页面入口&quot;">​</a></h2><p>资产页快捷功能栏「存入资金」，或全部功能 → 存入资金，或现金页 → 转入。</p><h2 id="入金流程" tabindex="-1">入金流程 <a class="header-anchor" href="#入金流程" aria-label="Permalink to &quot;入金流程&quot;">​</a></h2><ol><li><strong>选择入金货币</strong>：港元（HKD）或美元（USD）</li><li><strong>选择银行卡</strong>：从已绑定银行卡中选择，或点击「选择其他银行卡」新增</li><li><strong>按指引完成操作</strong>：在银行端完成转账，部分方式需在 App 上传汇款凭证</li></ol><blockquote><p>资金到账后可通过「货币兑换」功能兑换为其他币种。</p></blockquote><hr><h2 id="港元-hkd-入金" tabindex="-1">港元（HKD）入金 <a class="header-anchor" href="#港元-hkd-入金" aria-label="Permalink to &quot;港元（HKD）入金&quot;">​</a></h2><h3 id="入金方式" tabindex="-1">入金方式 <a class="header-anchor" href="#入金方式" aria-label="Permalink to &quot;入金方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th>入金方式</th><th>操作终端</th><th>最快到账</th></tr></thead><tbody><tr><td>银证转账</td><td>银行 App / 网银</td><td>约 5 分钟</td></tr><tr><td>eDDA 入金</td><td>银行 App / 网银</td><td>约 5 分钟</td></tr><tr><td>FPS 转数快</td><td>银行 App / 网银，需上传凭证</td><td>约 2 小时</td></tr><tr><td>网银转账</td><td>银行网银，需上传凭证</td><td>同行约 2 小时；跨行 1~3 个交易日</td></tr></tbody></table><h3 id="支持香港银行" tabindex="-1">支持香港银行 <a class="header-anchor" href="#支持香港银行" aria-label="Permalink to &quot;支持香港银行&quot;">​</a></h3><blockquote><p>完整的香港银行列表及各银行支持的入金方式（eDDA / FPS / 银证），请参阅<a href="/wiki/deposit/香港综合账户入金/支持银行列表">支持银行列表</a>。</p></blockquote><hr><h2 id="美元-usd-入金" tabindex="-1">美元（USD）入金 <a class="header-anchor" href="#美元-usd-入金" aria-label="Permalink to &quot;美元（USD）入金&quot;">​</a></h2><p>美元入金主要通过**电汇（Wire Transfer）**方式，在银行端完成转账后需在 App 上传汇款凭证通知长桥收款。</p><blockquote><p>支持的香港及境外银行（新加坡、澳大利亚、美国、马来西亚）完整列表，请参阅<a href="/wiki/deposit/香港综合账户入金/支持银行列表">支持银行列表</a>。</p></blockquote><hr><h2 id="管理银行卡" tabindex="-1">管理银行卡 <a class="header-anchor" href="#管理银行卡" aria-label="Permalink to &quot;管理银行卡&quot;">​</a></h2><p>进入路径：存入资金 → 管理银行卡。</p><p>每张绑定银行卡显示：</p><ul><li>银行名称</li><li>卡号（部分遮蔽，仅显示末四位）</li><li>eDDA 授权状态（已授权 / 未授权）</li></ul><p><strong>出金认证说明：</strong></p><ul><li>根据监管要求，出金只能使用已完成出金认证的银行卡</li><li>认证方式包括：银证授权、eDDA 授权、银行资料认证、入金成功等</li><li>每位用户最多绑定两家银行（每家银行可绑定多张卡）</li></ul>',25)])])}const b=a(d,[["render",l]]);export{u as __pageData,b as default};
